// Get snippets from Pinecone Assistant
const snippets = $json.snippets || [];

// Get current question and conversation history
const chatInput = $('Webhook').item.json.body.question;
const conversationHistory = $('Webhook').item.json.body.conversation_history || [];

// Filter for high-confidence results
const highConfidenceSnippets = snippets.filter(s => s.score > 0.75);

// Build context with sources
const contextWithSources = highConfidenceSnippets.map((s, index) => {
  const source = s.metadata?.file?.name || s.reference?.file?.name || 'Unknown source';
  return `[Source ${index + 1}: ${source}]\n${s.content}`;
}).join('\n\n---\n\n');

const hasGoodContext = highConfidenceSnippets.length > 0;

// Extract unique sources
const sources = [...new Set(highConfidenceSnippets.map(s => 
  s.metadata?.file?.name || s.reference?.file?.name || 'Unknown'
))];
const sourcesList = sources.map((s, i) => `[${i + 1}] ${s}`).join('\n');

// Build conversation context (last 3 turns)
const recentHistory = conversationHistory.slice(-6); // Last 3 Q&A pairs
const historyText = recentHistory.length > 0 
  ? `\n\nPrevious conversation:\n${recentHistory.map(msg => `${msg.role}: ${msg.content}`).join('\n')}`
  : '';

return {
  json: {
    messages: [
      {
        role: 'system',
        content: 'You are a helpful assistant. Answer ONLY based on the provided context. If the user message says you do not have confident information, respond with exactly that — do not answer from your own knowledge under any circumstances.'
      },
      {
        role: 'user',
        content: hasGoodContext
          ? `Context:\n${contextWithSources}${historyText}\n\nCurrent question: ${chatInput}\n\nInstructions:\n1. Answer using context and conversation history\n2. Be concise (2-3 sentences)\n3. End with:\n\nSources:\n[1] filename.pdf\n\nAvailable sources:\n${sourcesList}`
          : `I don't have confident information about "${chatInput}" in my knowledge base.`
      }
    ],
    conversation_history: conversationHistory,
    current_question: chatInput
  }
};
